// frontend/src/components/Dashboard/Dashboard.js
import React, { useState } from 'react';
import {
  Container,
  Grid,
  Box,
  AppBar,
  Toolbar,
  IconButton,
  Typography,
  Menu,
  MenuItem,
  Avatar,
  Divider,
  Button,
  useTheme,
  useMediaQuery,
  Tooltip
} from '@mui/material';
import {
  AccountCircle,
  Logout,
  Refresh,
  Sync,
  Visibility,
  VisibilityOff,
  AdminPanelSettings
} from '@mui/icons-material';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import { toast } from 'react-toastify';
import dashboardService from '../../services/dashboardService';

import StatsCards from './StatsCards';
import OpenPositions from './OpenPositions';
import ClosedOperationsModal from './ClosedOperationsModal';
import HistoricoTrades from './HistoricoTrades';
import Profile from './Profile';
import FuturesBalanceCard from './FuturesBalanceCard';

const Dashboard = () => {
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('sm'));
  const navigate = useNavigate();
  const { user, logout, setUser } = useAuth();

  const [anchorEl, setAnchorEl] = useState(null);
  const [showProfile, setShowProfile] = useState(false);
  const [showClosedOperations, setShowClosedOperations] = useState(false);
  const [hideValues, setHideValues] = useState(false);
  const [autoSync, setAutoSync] = useState(false);

  const handleMenu = (event) => {
    setAnchorEl(event.currentTarget);
  };

  const handleClose = () => {
    setAnchorEl(null);
  };

  const handleProfile = () => {
    setShowProfile(true);
    handleClose();
  };

  const handleLogout = async () => {
    try {
      await logout();
      navigate('/login');
    } catch (error) {
      toast.error('Erro ao fazer logout');
    }
    handleClose();
  };

  const handleSync = async () => {
    try {
      await dashboardService.syncTrades();
      toast.success('Trades sincronizados com sucesso');
    } catch (error) {
      toast.error(error.message || 'Erro ao sincronizar trades');
    }
  };

  const toggleAutoSync = async () => {
    try {
      if (autoSync) {
        await dashboardService.stopAutoSync();
        setAutoSync(false);
        toast.info('Auto-sync desativado');
      } else {
        await dashboardService.startAutoSync();
        setAutoSync(true);
        toast.success('Auto-sync ativado');
      }
    } catch (error) {
      toast.error(error.message || 'Erro ao alterar auto-sync');
    }
  };

  const handleUserUpdate = (updatedUser) => {
    setUser(updatedUser);
  };

  return (
    <Box sx={{ flexGrow: 1, minHeight: '100vh', bgcolor: 'background.default' }}>
      {/* Barra Superior */}
      <AppBar position="static" color="transparent" elevation={0}>
        <Toolbar>
          <Typography variant="h6" component="div" sx={{ flexGrow: 1 }}>
            Nautilus Automação
          </Typography>

          {/* Botões de ação */}
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
            {user?.is_admin && (
              <Tooltip title="Painel Admin">
                <IconButton color="inherit" onClick={() => navigate('/admin')}>
                  <AdminPanelSettings />
                </IconButton>
              </Tooltip>
            )}

            <Tooltip title={autoSync ? 'Desativar Auto-Sync' : 'Ativar Auto-Sync'}>
              <Button
                variant="outlined"
                color={autoSync ? 'success' : 'primary'}
                startIcon={<Sync />}
                onClick={toggleAutoSync}
                size="small"
              >
                Auto-Sync {autoSync ? 'ON' : 'OFF'}
              </Button>
            </Tooltip>

            <Tooltip title="Atualizar dados">
              <IconButton onClick={handleSync}>
                <Refresh />
              </IconButton>
            </Tooltip>

            <Tooltip title={hideValues ? 'Mostrar valores' : 'Ocultar valores'}>
              <IconButton onClick={() => setHideValues(!hideValues)}>
                {hideValues ? <VisibilityOff /> : <Visibility />}
              </IconButton>
            </Tooltip>

            <IconButton
              size="large"
              onClick={handleMenu}
              color="inherit"
            >
              <Avatar sx={{ width: 32, height: 32 }}>
                <AccountCircle />
              </Avatar>
            </IconButton>
          </Box>

          <Menu
            anchorEl={anchorEl}
            open={Boolean(anchorEl)}
            onClose={handleClose}
            onClick={handleClose}
          >
            <MenuItem disabled>
              <Typography variant="body2" color="textSecondary">
                {user?.email} {user?.id && `(ID: #${user.id})`}
              </Typography>
            </MenuItem>
            <MenuItem onClick={handleProfile}>
              <AccountCircle sx={{ mr: 2 }} />
              Perfil
            </MenuItem>
            <MenuItem onClick={handleLogout}>
              <Logout sx={{ mr: 2 }} />
              Sair
            </MenuItem>
          </Menu>
        </Toolbar>
      </AppBar>

      {/* Conteúdo Principal */}
      <Container maxWidth="xl">
        <Box sx={{ flexGrow: 1, py: 3 }}>
          <Grid container spacing={3}>
            {/* Cards de Estatísticas */}
            <Grid item xs={12}>
              <StatsCards hideValues={hideValues} />
            </Grid>

            {/* Saldo da Conta de Futuros */}
            <Grid item xs={12}>
              <FuturesBalanceCard hideValues={hideValues} />
            </Grid>

            {/* Posições Abertas */}
            <Grid item xs={12}>
              <OpenPositions hideValues={hideValues} />
            </Grid>

            {/* Operações Encerradas */}
            <Grid item xs={12}>
              <Box sx={{ 
                p: 3, 
                bgcolor: 'background.paper', 
                borderRadius: 2, 
                boxShadow: 1,
                border: `1px solid ${theme.palette.divider}`
              }}>
                <Box sx={{ 
                  display: 'flex', 
                  justifyContent: 'space-between', 
                  alignItems: 'center',
                  mb: 2
                }}>
                  <Typography variant="h6" sx={{ fontWeight: 'bold' }}>
                    📈 Operações Encerradas
                  </Typography>
                  <Button 
                    variant="contained" 
                    color="primary"
                    onClick={() => setShowClosedOperations(true)}
                    sx={{ 
                      borderRadius: 2,
                      textTransform: 'none',
                      fontWeight: 'bold'
                    }}
                  >
                    Ver Operações Encerradas
                  </Button>
                </Box>
                <Typography variant="body2" color="text.secondary">
                  Visualize o histórico completo de suas operações encerradas com estatísticas detalhadas.
                </Typography>
              </Box>
            </Grid>

            {/* Histórico de Trades */}
            <Grid item xs={12}>
              <HistoricoTrades hideValues={hideValues} />
            </Grid>
          </Grid>
        </Box>
      </Container>

      {/* Modal de Perfil */}
      <Profile
        open={showProfile}
        onClose={() => setShowProfile(false)}
        user={user}
        onUserUpdate={handleUserUpdate}
      />

      {/* Modal de Operações Encerradas */}
      <ClosedOperationsModal
        open={showClosedOperations}
        onClose={() => setShowClosedOperations(false)}
      />
    </Box>
  );
};

export default Dashboard;
